        var bowDetect = enemy.curWeapon === 9 && enemy.oldWeapon !== 9 || enemy.curWeapon === 12 && enemy.oldWeapon === 9 || enemy.curWeapon === 15 && enemy.oldWeapon === 12;
        if (distance > 300 && lookingAt && bowDetect) enemy.rangedBowInsta = true;
