            var obj = this.#nearObjects[i];
            if (!obj.active) continue;
            if (!obj.cactus && !(obj.dmg > 0 && obj.group && obj.group.id === 2)) continue;
            if (obj.owner && obj.owner.sid === enemy.sid) continue;
            var spikeScale = objSpikeScale(obj) + enemy.scale;
