        var spike = this.#pushObjs[0];
        var sScale = objSpikeScale(spike);
        var distToEnemy = Math.sqrt((ex - me.x2) * (ex - me.x2) + (ey - me.y2) * (ey - me.y2));
        var tau = angleDist(Z, Math.atan2(vecY, vecX));
        var decide = (ex - spike.x) * (ex - spike.x) + (ey - spike.y) * (ey - spike.y) <= (sScale + 38.75) * (sScale + 38.75);
        var opposite = 3600 + distToEnemy * distToEnemy - (28.5 + (decide ? 71.5 : 0)) * distToEnemy * Math.cos(tau);
        var deviance = Math.acos((distToEnemy * distToEnemy + opposite - 3600) / (2 * distToEnemy * Math.sqrt(opposite)));
