                            if (bObj.hitter && hw && bObj.hitter.reloads) { var rl = bObj.hitter.reloads[hw.type]; if (rl) ticksOut = Math.max(0, rl.max - rl.current); }
                            if (bObj.hitter && bObj.hitter !== player && !isAlly(bObj.hitter.sid)) breakerSID = bObj.hitter.sid;
