                if (rFound) { rFound.angle = rp.angle; rFound.type = 5; rFound.x = rp.x; rFound.y = rp.y; rFound.scale = items.list[rp.id].scale; rFound.ticksOut = rTicksOut; rFound.time = Date.now(); rFound.predictedBreakMS = rPredicted; rFound.breakerSID = rBreakerSID; rFound.retrap = true; rFound.retrapEnemy = rp.enemy; rFound.ownBreak = rOwnBreak || rFound.ownBreak; }
                else { this.preplaceTargets.push({ type: 5, angle: rp.angle, x: rp.x, y: rp.y, scale: items.list[rp.id].scale, ticksOut: rTicksOut, time: Date.now(), breakSid: combatManager.retrapSID, predictedBreakMS: rPredicted, breakerSID: rBreakerSID, retrap: true, retrapEnemy: rp.enemy, ownBreak: rOwnBreak }); preplace.requestFreshPing(); }
