            if (t.ownBreak && this.#ownFireAt[t.breakSid] && Date.now() - this.#ownFireAt[t.breakSid] < 300) continue;
            if (suppress && !t.ownBreak) continue;
            if (t.ownBreak && combatManager.player.trapped) continue;
            if (config.packets > 60 && !t.retrap && !t.ownBreak) continue;
