    for (var s = 0; s < 3; ++s) { dOT.ringProbe[s].x2 = 0; dOT.ringProbe[s].y2 = ey; dOT.ringProbe[s].vx = 0; dOT.ringProbe[s].vy = 0; }
    var vp = dOT.ringVP;
    vp.y2 = ey; vp.vx = 0; vp.vy = 0; vp.tailIndex = player.tailIndex; vp.buildIndex = player.buildIndex; vp.weaponIndex = fireWeapon; vp.zIndex = player.zIndex; vp.skinIndex = fireHat;
    var lo = null, hi = null;
