        var pfx = player.predicted ? player.predicted.likely.x : player.x2;
        var pfy = player.predicted ? player.predicted.likely.y : player.y2;
        var efx = enemy.predicted ? enemy.predicted.likely.x : enemy.x2;
        var efy = enemy.predicted ? enemy.predicted.likely.y : enemy.y2;
        var angle = Math.atan2(efy - pfy, efx - pfx);
