        var relx = o.x - ex, rely = o.y - ey;
        var t = relx * c + rely * s;
        if (t <= 0) continue;
        var colR = isTrap ? (o.scale - outlineWidth + 1) : (objSpikeScale(o) + enemy.scale);
        var perp = Math.abs(relx * s - rely * c);
        if (perp > colR) continue;
        var contact = t - Math.sqrt(colR * colR - perp * perp);
