var lastServerHTML = "";
function setupServerStatus() {
    var tmpHTML = "";

    var overallTotal = 0;
    for (var region in vultrClient.servers) {
        var serverList = vultrClient.servers[region];

        var totalPlayers = 0;
        for (var i = 0; i < serverList.length; i++) {
            totalPlayers += serverList[i].playerCount;
        }
        overallTotal += totalPlayers;

        var regionName = (vultrClient.regionInfo[region] || {}).name || region;
        tmpHTML += "<option disabled>" + regionName + " - " + totalPlayers + " players</option>";

        for (var serverIndex = 0; serverIndex < serverList.length; serverIndex++) {
            var server = serverList[serverIndex];
            var serverLabel = regionName + " " + server.name + " [" +
                Math.min(server.playerCount, server.playerCapacity) + "/" + server.playerCapacity + "]";
            if (server.ping != undefined && server.pings && server.pings.length >= 2) {
                serverLabel += " [" + Math.floor(server.ping) + "ms]";
            } else if (!server.selected) {
                serverLabel += " [?]";
            }
            var serverID = server.region + ":" + server.name;
            if (server.selected && partyButton) {
                var partySpan = partyButton.getElementsByTagName("span")[0];
                if (partySpan) partySpan.innerText = serverID;
            }
            tmpHTML += "<option value='" + serverID + "' " + (server.selected ? "selected" : "") + ">" + serverLabel + "</option>";
        }

        tmpHTML += "<option disabled></option>";
    }

    tmpHTML += "<option disabled>All Servers - " + overallTotal + " players</option>";

    if (tmpHTML !== lastServerHTML) {
        lastServerHTML = tmpHTML;
        serverSelect.innerHTML = tmpHTML;
    }

    var altServerText;
    var altServerURL;
    if (location.hostname == "sandbox.moomoo.io") {
        altServerText = "Back to MooMoo";
        altServerURL = "//moomoo.io/";
    } else {
        altServerText = "Try the sandbox";
        altServerURL = "//sandbox.moomoo.io/";
    }
    document.getElementById("altServer").innerHTML = "<a href='" + altServerURL + "'>" + altServerText + "<i class='material-icons' style='font-size:10px;vertical-align:middle'>arrow_forward_ios</i></a>";
}
vultrClient.onPingUpdate = function() {
    setupServerStatus();
};
function updateServerList() {
    return fetch(apiBase + "/servers?v=1.27").then(function(res) {
        return res.json();
    }).then(function(list) {
        return vultrClient.processServers(list);
    }).then(function() {
        setupServerStatus();
    }).catch(function(err) {
        console.error("Failed to load server data with status code:", err);
    });
}

serverSelect.addEventListener("change", UTILS.checkTrusted(function() {
    let parts = serverSelect.value.split(":");
    vultrClient.switchServer(parts[0], parts[1]);
}));

