var textStore = new Map();
var textLoose = [];
function showText(x, y, value) {
    if (!settings.visuals.dmgText) {
        textManager.showText(x, y, 50, 0.18, 500, Math.abs(value), (value >= 0) ? "#fff" : "#8ecc51", null, 0);
        return;
    }
    var isHeal = value < 0, mag = Math.abs(value);
    var target = nearestTextTarget(x, y);
    if (!isHeal && (!target || target.isPlayer)) return;
    if (target) {
        var key = target.sid * 4 + (target.isPlayer ? 0 : 2) + (isHeal ? 1 : 0);
        var e = textStore.get(key);
        if (e) e.sum += mag;
        else textStore.set(key, { sum: mag, x: x, y: y, isHeal: isHeal, target: target });
    } else if (textLoose.length < 400) {
        textLoose.push({ x: x, y: y, value: value });
    }
}
function nearestTextTarget(x, y) {
    var best = null, bestD = Infinity;
    for (var i = 0; i < players.length; ++i) {
        var p = players[i];
        if (!p.visible) continue;
        var dx = p.x2 - x, dy = p.y2 - y, d = dx * dx + dy * dy;
        if (d >= bestD) continue;
        var pvx = p.vx || 0, pvy = p.vy || 0, r = 3.5 + Math.sqrt(pvx * pvx + pvy * pvy);
        if (d <= r * r) { bestD = d; best = p; }
    }
    for (var j = 0; j < ais.length; ++j) {
        var a = ais[j];
        if (!a.active || !a.visible) continue;
        var adx = a.x2 - x, ady = a.y2 - y, ad = adx * adx + ady * ady;
        if (ad >= bestD) continue;
        var avx = a.x1 != null ? a.x2 - a.x1 : 0, avy = a.y1 != null ? a.y2 - a.y1 : 0, ar = 3.5 + Math.sqrt(avx * avx + avy * avy);
        if (ad <= ar * ar) { bestD = ad; best = a; }
    }
    return best;
}
function flushTextBuffer() {
    for (var pi = 0; pi < players.length; ++pi) {
        var pp = players[pi];
        if (!(pp.stackDmg > 0)) continue;
        if (pp.visible) textManager.showText(pp.x2, pp.y2, 50, 0.15, 800, Math.round(pp.stackDmg), customColor(pp.sid), "Lilita One");
        pp.stackDmg = -1;
    }
    textStore.forEach(function(e) {
        var color = e.isHeal ? (settings.visuals.uiMetrics ? "#7A9874" : "#8ecc51") : (e.target.isPlayer ? customColor(e.target.sid) : "#fff");
        textManager.showText(e.x, e.y, 50, 0.15, 800, Math.round(e.sum), color, "Lilita One");
    });
    textStore.clear();
    if (!textLoose.length) return;
    var groups = [];
    for (var i = 0; i < textLoose.length; ++i) {
        var tb = textLoose[i], isHeal = tb.value < 0, g = null;
        for (var k = 0; k < groups.length; ++k) {
            var gg = groups[k];
            if (gg.isHeal === isHeal && Math.abs(gg.x - tb.x) < 3.5 && Math.abs(gg.y - tb.y) < 3.5) { g = gg; break; }
        }
        if (!g) { g = { x: tb.x, y: tb.y, sum: 0, isHeal: isHeal }; groups.push(g); }
        g.sum += Math.abs(tb.value);
    }
    for (var m = 0; m < groups.length; ++m) {
        var grp = groups[m];
        textManager.showText(grp.x, grp.y, 50, 0.15, 800, Math.round(grp.sum), grp.isHeal ? (settings.visuals.uiMetrics ? "#7A9874" : "#8ecc51") : "#fff", "Lilita One");
    }
    textLoose.length = 0;
}

