function canDealPoison(p, weaponId) {
    var w = items.weapons[weaponId];
    if (!w) return 0;
    var variant = (w.type === 0 ? p.variantPrimary : p.variantSecondary) || 0;
    if (variant === 3) return 5;
    if (p.skinIndex === 21) return 6;
    return 0;
}

function gatherAnimation(sid, didHit, index) {
    tmpObj = findPlayerBySID(sid);
    if (tmpObj) {
        tmpObj.startAnim(didHit, index);
        if (settings.visuals.trapGhosts && didHit && tmpObj !== player && tmpObj.sid != null && !isAlly(tmpObj.sid)) trapGhostFromSwing(tmpObj, index);

        var weapon = items.weapons[index];
        if (weapon && weapon.speed) hitResolver.pendingHits.push({ player: tmpObj, type: weapon.type, weaponId: index });

        if (weapon) {
            var pCount = canDealPoison(tmpObj, index);
            if (pCount > 0) {
                var aimDir = tmpObj.d2;
                for (var pe = 0; pe < combatIntel.enemies.length; ++pe) {
                    var en = combatIntel.enemies[pe];
                    if (en.sid === tmpObj.sid || (en.team && tmpObj.team && en.team === tmpObj.team)) continue;
                    var pdx = en.x2 - tmpObj.x2, pdy = en.y2 - tmpObj.y2;
                    var pr = combatManager.weaponReach(en, index);
                    if (pdx * pdx + pdy * pdy > pr * pr) continue;
                    if (UTILS.getAngleDist(aimDir, Math.atan2(pdy, pdx)) > config.gatherAngle) continue;
                    en.poisonCount = pCount;
                }
            }
        }
    }
}

function createSpikeKB(enemy, landX, landY) {
    if (!settings.visuals.kbGhost) return;
    if (!enemy || Date.now() - kbLastVisualTime < 730) return;
    var kdx = landX - enemy.x2, kdy = landY - enemy.y2;
    var kdist = Math.sqrt(kdx * kdx + kdy * kdy);
    if (kdist === 0) return;
    var kslide = Math.min(kdist, 170), kdir = Math.atan2(kdy, kdx);
    var ghost = Object.assign({}, enemy);
    ghost.fake = true;
    ghost.visible = true;
    ghost.vals = 0.5;
    ghost.NEWX = enemy.x2 + Math.cos(kdir) * kslide;
    ghost.NEWY = enemy.y2 + Math.sin(kdir) * kslide;
    ghost.x = enemy.x2; ghost.y = enemy.y2;
    ghost.x1 = enemy.x2; ghost.y1 = enemy.y2;
    ghost.x2 = ghost.NEWX; ghost.y2 = ghost.NEWY;
    ghost.dir = enemy.dir;
    ghost.dt = 0;
    ghost.expire = 3;
    fakePlayers.push(ghost);
    kbLastVisualTime = Date.now();
}

function createDeathGhost(deadPlayer) {
    if (!settings.visuals.deathGhost) return;
    if (!player || deadPlayer === player) return;
    var gx = deadPlayer.x != null ? deadPlayer.x : deadPlayer.x2;
    var gy = deadPlayer.y != null ? deadPlayer.y : deadPlayer.y2;
    if (gx == null || gy == null) return;
    var mgx = player.x2 != null ? player.x2 : player.x, mgy = player.y2 != null ? player.y2 : player.y;
    if (mgx != null && mgy != null) {
        var mdx = gx - mgx, mdy = gy - mgy;
        if (mdx * mdx + mdy * mdy > 500 * 500) return;
    }
    var ghost = Object.assign({}, deadPlayer);
    ghost.fake = true;
    ghost.deathGhost = true;
    ghost.visible = true;
    ghost.vals = 0.77;
    ghost.skinColor = 4;
    ghost.skinIndex = 48;
    ghost.tailIndex = 13;
    ghost.buildIndex = -1;
    ghost.dirPlus = 0;
    ghost.x = gx; ghost.y = gy;
    ghost.driftDir = Math.atan2(gy - player.y, gx - player.x);
    ghost.driftSpeed = 0.35;
    ghost.fadeRate = 0.000278;
    fakePlayers.push(ghost);
}

var shatters = [];
var shatterCfg = { jiggle: 1100, fly: 1300, fade: 1250, fadeLead: 350, edge: 8.5 };

function shatterClip(poly, mx, my, nx, ny) {
    var out = [];
    for (var i = 0; i < poly.length; ++i) {
        var a = poly[i], b = poly[(i + 1) % poly.length];
        var da = (a.x - mx) * nx + (a.y - my) * ny, db = (b.x - mx) * nx + (b.y - my) * ny;
        if (da <= 0) out.push(a);
        if ((da < 0) !== (db < 0)) { var t = da / (da - db); out.push({ x: a.x + (b.x - a.x) * t, y: a.y + (b.y - a.y) * t }); }
    }
    return out;
}

function makeShatterPieces(R, n) {
    var seeds = [];
    for (var i = 0; i < n; ++i) { var a = Math.random() * Math.PI * 2, rr = Math.sqrt(Math.random()) * R * 0.72; seeds.push({ x: Math.cos(a) * rr, y: Math.sin(a) * rr }); }
    var M = 24, bound = [];
    for (var i = 0; i < M; ++i) { var a = i / M * Math.PI * 2; bound.push({ x: Math.cos(a) * R, y: Math.sin(a) * R }); }
    var pieces = [], cracks = [];
    for (var i = 0; i < n; ++i) {
        var poly = bound;
        for (var j = 0; j < n && poly.length >= 3; ++j) {
            if (j === i) continue;
            poly = shatterClip(poly, (seeds[i].x + seeds[j].x) / 2, (seeds[i].y + seeds[j].y) / 2, seeds[j].x - seeds[i].x, seeds[j].y - seeds[i].y);
        }
        if (poly.length < 3) continue;
        var mx = 0, my = 0;
        for (var k = 0; k < poly.length; ++k) { mx += poly[k].x; my += poly[k].y; }
        mx /= poly.length; my /= poly.length;
        var cd = Math.hypot(mx, my) || 0.001;
        pieces.push({ poly: poly, dirX: mx / cd, dirY: my / cd, cdist: cd, base: 32 + Math.random() * 26 });
        for (var k = 0; k < poly.length; ++k) {
            var q0 = poly[k], q1 = poly[(k + 1) % poly.length];
            if (Math.hypot((q0.x + q1.x) / 2, (q0.y + q1.y) / 2) < R - 4) cracks.push([q0.x, q0.y, q1.x, q1.y]);
        }
    }
    return { pieces: pieces, cracks: cracks };
}

function makeWeaponThrow(snap) {
    var weapon = items.weapons[snap.weaponIndex];
    if (!weapon || !weapon.length) return null;
    return {
        dist: 105 + Math.random() * 40,
        perp: (Math.random() - 0.5) * 30,
        spin: (Math.random() < 0.5 ? 1 : -1) * (1.7 + Math.random() * 1.5)
    };
}

function makeTailThrow(snap) {
    if (!(snap.tailIndex > 0)) return null;
    return {
        dist: 105 + Math.random() * 40,
        perp: (Math.random() - 0.5) * 30,
        spin: (Math.random() < 0.5 ? 1 : -1) * (1.7 + Math.random() * 1.5)
    };
}

var shatterScratchCanvas = null;
function getShatterScratch(size) {
    size = Math.ceil(size);
    if (!shatterScratchCanvas) shatterScratchCanvas = document.createElement("canvas");
    if (shatterScratchCanvas.width < size) shatterScratchCanvas.width = shatterScratchCanvas.height = size;
    var sctx = shatterScratchCanvas.getContext("2d");
    sctx.setTransform(1, 0, 0, 1, 0, 0);
    sctx.globalAlpha = 1;
    sctx.globalCompositeOperation = "source-over";
    sctx.clearRect(0, 0, size, size);
    return { canvas: shatterScratchCanvas, ctx: sctx, size: size };
}

function createShatter(deadPlayer) {
    if (!settings.visuals.deathShatter || !player || deadPlayer === player) return;
    var gx = deadPlayer.x != null ? deadPlayer.x : deadPlayer.x2, gy = deadPlayer.y != null ? deadPlayer.y : deadPlayer.y2;
    if (gx == null || gy == null) return;
    var mgx = player.x2 != null ? player.x2 : player.x, mgy = player.y2 != null ? player.y2 : player.y;
    if (mgx != null && mgy != null) { var mdx = gx - mgx, mdy = gy - mgy; if (mdx * mdx + mdy * mdy > 500 * 500) return; }
    var snap = Object.assign({}, deadPlayer);
    snap.buildIndex = -1;
    var R = snap.scale;
    if (snap.skinIndex > 0) { var shatterHat = store.hatById[snap.skinIndex]; if (shatterHat) R = Math.max(R, shatterHat.scale / 2); }
    R += outlineWidth;
    var built = makeShatterPieces(R, 9 + Math.floor(Math.random() * 3));
    var bufHalf = R + outlineWidth * 2;
    var buf = document.createElement("canvas");
    buf.width = buf.height = Math.ceil(bufHalf * 2);
    var buftx = buf.getContext("2d");
    buftx.translate(bufHalf, bufHalf);
    var bufTail = snap.tailIndex; snap.tailIndex = 0;
    snap.hideWeapon = true;
    buftx.strokeStyle = outlineColor;
    renderPlayer(snap, buftx);
    snap.hideWeapon = false;
    snap.tailIndex = bufTail;
    var maxFly = 0;
    for (var mf = 0; mf < built.pieces.length; ++mf) { var fd = built.pieces[mf].base + built.pieces[mf].cdist * 1.5; if (fd > maxFly) maxFly = fd; }
    shatters.push({ snap: snap, x: gx, y: gy, dir: (deadPlayer.dir || 0) + (deadPlayer.dirPlus || 0), born: Date.now(), R: R, pieces: built.pieces, cracks: built.cracks, throwW: makeWeaponThrow(snap), throwT: makeTailThrow(snap), buf: buf, bufHalf: bufHalf, spread: R + maxFly + outlineWidth * 2 });
}

function drawShatterWeapon(sh, ox, oy, flingEase, alpha) {
    if (!sh.throwW) return;
    var weapon = items.weapons[sh.snap.weaponIndex];
    if (!weapon) return;
    var tw = sh.throwW, wcx = sh.snap.scale + (weapon.xOff || 0), wcy = weapon.yOff || 0;
    var variantSrc = (config.weaponVariants[sh.snap.weaponVariant] || config.weaponVariants[0]).src;
    mainContext.save();
    mainContext.globalAlpha = alpha;
    mainContext.translate(ox, oy);
    mainContext.rotate(sh.dir);
    mainContext.translate(wcx + tw.dist * flingEase, wcy + tw.perp * flingEase);
    mainContext.rotate(tw.spin * flingEase);
    mainContext.translate(-wcx, -wcy);
    renderTool(weapon, variantSrc, sh.snap.scale, 0, mainContext);
    mainContext.restore();
}

function drawShatterTail(sh, ox, oy, flingEase, alpha) {
    if (!sh.throwT || !(sh.snap.tailIndex > 0)) return;
    var acc = accessPointers[sh.snap.tailIndex];
    var tcx = -20 - ((acc && acc.xOff) || 0), tcy = 0, tt = sh.throwT;
    mainContext.save();
    mainContext.globalAlpha = alpha;
    mainContext.translate(ox, oy);
    mainContext.rotate(sh.dir);
    mainContext.translate(tcx - tt.dist * flingEase, tcy + tt.perp * flingEase);
    mainContext.rotate(tt.spin * flingEase);
    mainContext.translate(-tcx, -tcy);
    renderTail(sh.snap.tailIndex, mainContext, sh.snap);
    mainContext.restore();
}

function renderShatters(xOffset, yOffset) {
    if (!shatters.length) return;
    var now = Date.now(), total = shatterCfg.jiggle + shatterCfg.fly - shatterCfg.fadeLead + shatterCfg.fade;
    for (var s = shatters.length - 1; s >= 0; --s) {
        var sh = shatters[s], age = now - sh.born;
        if (age >= total) { shatters.splice(s, 1); continue; }
        var cx = sh.x - xOffset, cy = sh.y - yOffset, pcs = sh.pieces, R = sh.R, p, pc, poly, k, q0, q1;
        if (age < shatterCfg.jiggle) {
            var jp = age / shatterCfg.jiggle;
            var jx = cx + Math.sin(now / 25) * 2.75, jy = cy + Math.cos(now / 21) * 2.75;
            drawShatterTail(sh, jx, jy, 0, 1);
            var sc = getShatterScratch(sh.bufHalf * 2), sctx = sc.ctx;
            sctx.save();
            sctx.translate(sh.bufHalf, sh.bufHalf);
            sctx.drawImage(sh.buf, -sh.bufHalf, -sh.bufHalf);
            sctx.beginPath(); sctx.arc(0, 0, R * jp, 0, Math.PI * 2); sctx.clip();
            sctx.globalCompositeOperation = "source-atop";
            sctx.strokeStyle = outlineColor; sctx.lineWidth = outlineWidth; sctx.lineCap = "round"; sctx.lineJoin = "round";
            sctx.beginPath();
            for (k = 0; k < sh.cracks.length; ++k) { var cg = sh.cracks[k]; sctx.moveTo(cg[0], cg[1]); sctx.lineTo(cg[2], cg[3]); }
            sctx.stroke();
            sctx.restore();
            drawShatterWeapon(sh, jx, jy, 0, 1);
            mainContext.save();
            mainContext.globalAlpha = 1;
            mainContext.translate(jx, jy);
            mainContext.rotate(sh.dir);
            mainContext.drawImage(sc.canvas, 0, 0, sc.size, sc.size, -sh.bufHalf, -sh.bufHalf, sc.size, sc.size);
            mainContext.restore();
        } else {
            var ft = Math.min(1, (age - shatterCfg.jiggle) / shatterCfg.fly), ease = 1 - Math.pow(1 - ft, 3);
            var fadeStart = shatterCfg.jiggle + shatterCfg.fly - shatterCfg.fadeLead;
            var fade = age < fadeStart ? 1 : Math.max(0, 1 - (age - fadeStart) / shatterCfg.fade);
            var fc = getShatterScratch(sh.spread * 2), fctx = fc.ctx;
            fctx.save();
            fctx.translate(sh.spread, sh.spread);
            fctx.rotate(sh.dir);
            for (p = 0; p < pcs.length; ++p) {
                pc = pcs[p]; poly = pc.poly;
                var dist = (pc.base + pc.cdist * 1.5) * ease;
                fctx.save();
                fctx.translate(pc.dirX * dist, pc.dirY * dist);
                fctx.beginPath();
                fctx.moveTo(poly[0].x, poly[0].y);
                for (k = 1; k < poly.length; ++k) fctx.lineTo(poly[k].x, poly[k].y);
                fctx.closePath();
                fctx.clip();
                fctx.drawImage(sh.buf, -sh.bufHalf, -sh.bufHalf);
                fctx.restore();
            }
            fctx.globalCompositeOperation = "source-atop";
            fctx.strokeStyle = outlineColor; fctx.lineWidth = shatterCfg.edge; fctx.lineJoin = "round"; fctx.lineCap = "round";
            for (p = 0; p < pcs.length; ++p) {
                pc = pcs[p]; poly = pc.poly;
                var dist2 = (pc.base + pc.cdist * 1.5) * ease;
                fctx.save();
                fctx.translate(pc.dirX * dist2, pc.dirY * dist2);
                fctx.beginPath();
                for (k = 0; k < poly.length; ++k) {
                    q0 = poly[k]; q1 = poly[(k + 1) % poly.length];
                    if (Math.hypot((q0.x + q1.x) / 2, (q0.y + q1.y) / 2) < R - 4) { fctx.moveTo(q0.x, q0.y); fctx.lineTo(q1.x, q1.y); }
                }
                fctx.stroke();
                fctx.restore();
            }
            fctx.restore();
            var wEase = 1 - Math.pow(1 - Math.min(1, ft * 1.2), 3);
            drawShatterTail(sh, cx, cy, wEase, fade);
            drawShatterWeapon(sh, cx, cy, wEase, fade);
            mainContext.save();
            mainContext.globalAlpha = fade;
            mainContext.translate(cx, cy);
            mainContext.drawImage(fc.canvas, 0, 0, fc.size, fc.size, -sh.spread, -sh.spread, fc.size, fc.size);
            mainContext.restore();
        }
    }
}

function advanceFakeGhosts() {
    for (var i = 0; i < fakePlayers.length; ++i) {
        var g = fakePlayers[i];
        if (isNaN(g.expire)) continue;
        g.x1 = g.x; g.y1 = g.y;
        g.x2 = g.NEWX; g.y2 = g.NEWY;
        g.dt = 0;
        g.expire -= 1;
    }
    if (fakePlayers.length) fakePlayers = fakePlayers.filter(function (g) { return g.expire >= 0 || isNaN(g.expire); });
}

function renderPlayers(xOffset, yOffset, zIndex) {
    mainContext.globalAlpha = 1;
    var animAll = fakePlayers.length ? players.concat(fakePlayers) : players;
    for (var i = 0; i < animAll.length; ++i) {
        tmpObj = animAll[i];
        if (tmpObj.zIndex == zIndex) {
            if (tmpObj.animate) tmpObj.animate(delta);
            mainContext.globalAlpha = tmpObj.fake ? tmpObj.vals : 1;
            if (tmpObj.visible || tmpObj.fake) {
                tmpObj.skinRot += (0.002 * delta);
                tmpDir = tmpObj.deathGhost ? tmpObj.skinRot : (((tmpObj == player && !settings.visuals.ae86Aim)?(combatManager.bestAim != null ? combatManager.bestAim : getAttackDir()):tmpObj.dir) + tmpObj.dirPlus);
                mainContext.save();
                mainContext.translate(tmpObj.x - xOffset, tmpObj.y - yOffset);

                mainContext.rotate(tmpDir);
                renderPlayer(tmpObj, mainContext);
                mainContext.restore();
            }
        }
    }
    mainContext.globalAlpha = 1;
}

function renderPlayer(obj, ctxt) {
    ctxt = ctxt || mainContext;
    ctxt.lineWidth = outlineWidth;
    ctxt.lineJoin = "miter";
    var weapon = items.weapons[obj.weaponIndex];
    var handAngle = (Math.PI / 4) * (weapon.armS||1);
    var oHandAngle = (obj.buildIndex < 0)?(weapon.hndS||1):1;
    var oHandDist = (obj.buildIndex < 0)?(weapon.hndD||1):1;
    var variantSrc = (config.weaponVariants[obj.weaponVariant] || config.weaponVariants[0]).src;

    if (obj.tailIndex > 0) {
        renderTail(obj.tailIndex, ctxt, obj);
    }

    if (obj.buildIndex < 0 && !obj.hideWeapon && !weapon.aboveHand) {
        renderTool(weapon, variantSrc, obj.scale, 0, ctxt);
        if (weapon.projectile != undefined && !weapon.hideProjectile) {
            renderProjectile(obj.scale, 0,
                             items.projectiles[weapon.projectile], ctxt);
        }
    }

    ctxt.fillStyle = (typeof config.skinColors[obj.skinColor] === "string") ? config.skinColors[obj.skinColor] : config.skinColors[config.skinColors.length - 1];
    renderCircle(obj.scale * Math.cos(handAngle), (obj.scale * Math.sin(handAngle)), 14, ctxt);
    renderCircle((obj.scale * oHandDist) * Math.cos(-handAngle * oHandAngle),
                 (obj.scale * oHandDist) * Math.sin(-handAngle * oHandAngle), 14, ctxt);

    if (obj.buildIndex < 0 && !obj.hideWeapon && weapon.aboveHand) {
        renderTool(weapon, variantSrc, obj.scale, 0, ctxt);
        if (weapon.projectile != undefined && !weapon.hideProjectile) {
            renderProjectile(obj.scale, 0,
                             items.projectiles[weapon.projectile], ctxt);
        }
    }

    if (obj.buildIndex >= 0) {
        var buildItem = items.list[obj.buildIndex];
        var tmpSprite = getItemSprite(buildItem);
        ctxt.drawImage(tmpSprite, obj.scale - buildItem.holdOffset, -tmpSprite.width / 2);
    }

    renderCircle(0, 0, obj.scale, ctxt);

    if (obj.skinIndex > 0) {
        ctxt.rotate(Math.PI/2);
        renderSkin(obj.skinIndex, ctxt, null, obj);
    }
}

var skinSprites = {};
var skinPointers = {};
var tmpSkin;
function renderSkin(index, ctxt, parentSkin, owner) {
    tmpSkin = skinSprites[index];
    if (!tmpSkin) {
        var tmpImage = new Image();
        tmpImage.onload = function() {
            this.isLoaded = true;
            this.onload = null;
        };
        tmpImage.src = "./img/hats/hat_" + index + ".png";
        skinSprites[index] = tmpImage;
        tmpSkin = tmpImage;
    }
    var tmpObj = parentSkin||skinPointers[index];
    if (!tmpObj) {
        for (var i = 0; i < hats.length; ++i) {
            if (hats[i].id == index) {
                tmpObj = hats[i];
                break;
            }
        }
        skinPointers[index] = tmpObj;
    }
    if (tmpSkin.isLoaded)
        ctxt.drawImage(tmpSkin, -tmpObj.scale/2, -tmpObj.scale/2, tmpObj.scale, tmpObj.scale);
    if (!parentSkin && tmpObj.topSprite && (index !== 11 || !hatTxtEnabled(11))) {
        ctxt.save();
        ctxt.rotate(owner.skinRot);
        renderSkin(index + "_top", ctxt, tmpObj, owner);
        ctxt.restore();
    }
}

var accessSprites = {};
var accessPointers = {};
function renderTail(index, ctxt, owner) {
    tmpSkin = accessSprites[index];
    if (!tmpSkin) {
        var tmpImage = new Image();
        tmpImage.onload = function() {
            this.isLoaded = true;
            this.onload = null;
        };
        tmpImage.src = "./img/accessories/access_" + index + ".png";
        accessSprites[index] = tmpImage;
        tmpSkin = tmpImage;
    }
    var tmpObj = accessPointers[index];
    if (!tmpObj) {
        for (var i = 0; i < accessories.length; ++i) {
            if (accessories[i].id == index) {
                tmpObj = accessories[i];
                break;
            }
        }
        accessPointers[index] = tmpObj;
    }
    if (tmpSkin.isLoaded) {
        ctxt.save();
        ctxt.translate(-20 - (tmpObj.xOff||0), 0);
        if (tmpObj.spin)
            ctxt.rotate(owner.skinRot);
        ctxt.drawImage(tmpSkin, -(tmpObj.scale/2), -(tmpObj.scale/2), tmpObj.scale, tmpObj.scale);
        ctxt.restore();
    }
}

var toolSprites = {};
function renderTool(obj, variant, x, y, ctxt) {
    var tmpSrc = obj.src + (variant||"");
    var tmpSprite = toolSprites[tmpSrc];
    if (!tmpSprite) {
        tmpSprite = new Image();
        tmpSprite.onload = function() {
            this.isLoaded = true;
        }
        tmpSprite.src = "./img/weapons/" + tmpSrc + ".png";
        toolSprites[tmpSrc] = tmpSprite;
    }
    if (tmpSprite.isLoaded) {
        ctxt.drawImage(tmpSprite, x+obj.xOff-(obj.length/2), y+obj.yOff-(obj.width/2), obj.length, obj.width);
    }
}

var gameObjectSprites = {};
function getResSprite(obj) {
    if (obj.cachedSprite) return obj.cachedSprite;
    var biomeID = (obj.y>=config.mapScale-config.snowBiomeTop)?2:((obj.y<=config.snowBiomeTop)?1:0);
    var tmpIndex = (obj.type + "_" + obj.scale + "_" + biomeID);
    var tmpSprite = gameObjectSprites[tmpIndex];
    if (!tmpSprite) {
        var tmpCanvas = document.createElement('canvas');
        tmpCanvas.width = tmpCanvas.height = (obj.scale * 2.1) + outlineWidth;
        var tmpContext = tmpCanvas.getContext('2d');
        tmpContext.translate((tmpCanvas.width / 2), (tmpCanvas.height / 2));
        tmpContext.rotate(UTILS.randFloat(0, Math.PI));
        tmpContext.strokeStyle = outlineColor;
        tmpContext.lineWidth = outlineWidth;
        if (obj.type == 0) {
            var tmpScale;
            for (var i = 0; i < 2; ++i) {
                tmpScale = tmpObj.scale * (!i?1:0.5);
                renderStar(tmpContext, (tmpObj.sid % 2 === 0) ? 5 : 7, tmpScale, tmpScale * 0.7);
                tmpContext.fillStyle = !biomeID?(!i?"#9ebf57":"#b4db62"):(!i?"#e3f1f4":"#fff");
                tmpContext.fill();
                if (!i)
                    tmpContext.stroke();
            }
        } else if (obj.type == 1) {
            if (biomeID == 2) {
                tmpContext.fillStyle = "#606060";
                renderStar(tmpContext, 6, obj.scale * 0.3, obj.scale * 0.71);
                tmpContext.fill();
                tmpContext.stroke();
                tmpContext.fillStyle = "#89a54c";
                renderCircle(0, 0, obj.scale * 0.55, tmpContext);
                tmpContext.fillStyle = "#a5c65b";
                renderCircle(0, 0, obj.scale * 0.3, tmpContext, true);
            } else {
                renderBlob(tmpContext, 6, tmpObj.scale, tmpObj.scale * 0.7);
                tmpContext.fillStyle = biomeID?"#e3f1f4":"#89a54c";
                tmpContext.fill();
                tmpContext.stroke();
                tmpContext.fillStyle = biomeID?"#6a64af":"#c15555";
                var tmpRange;
                var berries = 4;
                var rotVal = mathPI2 / berries;
                for (var i = 0; i < berries; ++i) {
                    tmpRange = UTILS.randInt(tmpObj.scale/3.5, tmpObj.scale/2.3);
                    renderCircle(tmpRange * Math.cos(rotVal * i), tmpRange * Math.sin(rotVal * i),
                                 UTILS.randInt(10, 12), tmpContext);
                }
            }
        } else if (obj.type == 2 || obj.type == 3) {
            tmpContext.fillStyle = (obj.type==2)?(biomeID==2?"#938d77":"#939393"):"#e0c655";
            renderStar(tmpContext, 3, obj.scale, obj.scale);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.fillStyle = (obj.type==2)?(biomeID==2?"#b2ab90":"#bcbcbc"):"#ebdca3";
            renderStar(tmpContext, 3, obj.scale * 0.55, obj.scale * 0.65);
            tmpContext.fill();
        }
        tmpSprite = tmpCanvas;
        gameObjectSprites[tmpIndex] = tmpSprite;
    }
    obj.cachedSprite = tmpSprite;
    return tmpSprite;
}

var itemSprites = [];
function getItemSprite(obj, asIcon) {
    var enemySpike = settings.visuals.enemySpikeTint && player && obj.group && obj.group.id === 2 && obj.owner && !isAlly(obj.owner.sid);
    var spriteKey = enemySpike ? (obj.id + "e") : obj.id;
    var tmpSprite = itemSprites[spriteKey];
    if (!tmpSprite || asIcon) {
        var tmpCanvas = document.createElement('canvas');
        tmpCanvas.width = tmpCanvas.height = (obj.scale * 2.5) + outlineWidth +
            (items.list[obj.id].spritePadding||0);
        var tmpContext = tmpCanvas.getContext('2d');
        tmpContext.translate((tmpCanvas.width / 2), (tmpCanvas.height / 2));
        tmpContext.rotate(asIcon?0:(Math.PI/2));
        tmpContext.strokeStyle = outlineColor;
        tmpContext.lineWidth = outlineWidth * (asIcon?(tmpCanvas.width/81):1);
        if (obj.name == "apple") {
            tmpContext.fillStyle = "#c15555";
            renderCircle(0, 0, obj.scale, tmpContext);
            tmpContext.fillStyle = "#89a54c";
            var leafDir = -(Math.PI / 2);
            renderLeaf(obj.scale * Math.cos(leafDir), obj.scale * Math.sin(leafDir),
                       25, leafDir + Math.PI/2, tmpContext);
        } else if (obj.name == "cookie") {
            tmpContext.fillStyle = "#cca861";
            renderCircle(0, 0, obj.scale, tmpContext);
            tmpContext.fillStyle = "#937c4b";
            var chips = 4;
            var rotVal = mathPI2 / chips;
            var tmpRange;
            for (var i = 0; i < chips; ++i) {
                tmpRange = UTILS.randInt(obj.scale / 2.5, obj.scale / 1.7);
                renderCircle(tmpRange * Math.cos(rotVal * i), tmpRange * Math.sin(rotVal * i),
                             UTILS.randInt(4, 5), tmpContext, true);
            }
        } else if (obj.name == "cheese") {
            tmpContext.fillStyle = "#f4f3ac";
            renderCircle(0, 0, obj.scale, tmpContext);
            tmpContext.fillStyle = "#c3c28b";
            var chips = 4;
            var rotVal = mathPI2 / chips;
            var tmpRange;
            for (var i = 0; i < chips; ++i) {
                tmpRange = UTILS.randInt(obj.scale / 2.5, obj.scale / 1.7);
                renderCircle(tmpRange * Math.cos(rotVal * i), tmpRange * Math.sin(rotVal * i),
                             UTILS.randInt(4, 5), tmpContext, true);
            }
        } else if (obj.name == "wood wall" || obj.name == "stone wall" || obj.name == "castle wall") {
            tmpContext.fillStyle = (obj.name == "castle wall")?"#83898e":(obj.name=="wood wall")?
                "#a5974c":"#939393";
            var sides = (obj.name == "castle wall")?4:3;
            renderStar(tmpContext, sides, obj.scale * 1.1, obj.scale * 1.1);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.fillStyle = (obj.name == "castle wall")?"#9da4aa":(obj.name=="wood wall")?
                "#c9b758":"#bcbcbc";
            renderStar(tmpContext, sides, obj.scale * 0.65, obj.scale * 0.65);
            tmpContext.fill();
        } else if (obj.name == "spikes" || obj.name == "greater spikes" || obj.name == "poison spikes"
                   || obj.name == "spinning spikes") {
            tmpContext.fillStyle = enemySpike ? ((obj.name == "poison spikes") ? "#b1527a" : "#c15555") : ((obj.name == "poison spikes")?"#7b935d":"#939393");
            var tmpScale = (obj.scale * 0.6);
            renderStar(tmpContext, (obj.name == "spikes")?5:6, obj.scale, tmpScale);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.fillStyle = "#a5974c";
            renderCircle(0, 0, tmpScale, tmpContext);
            tmpContext.fillStyle = "#c9b758";
            renderCircle(0, 0, tmpScale/2, tmpContext, true);
        } else if (obj.name == "windmill" || obj.name == "faster windmill" || obj.name == "power mill") {
            tmpContext.fillStyle = "#a5974c";
            renderCircle(0, 0, obj.scale, tmpContext);
            tmpContext.fillStyle = "#c9b758";
            renderRectCircle(0, 0, obj.scale * 1.5, 29, 4, tmpContext);
            tmpContext.fillStyle = "#a5974c";
            renderCircle(0, 0, obj.scale * 0.5, tmpContext);
        } else if (obj.name == "mine") {
            tmpContext.fillStyle = "#939393";
            renderStar(tmpContext, 3, obj.scale, obj.scale);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.fillStyle = "#bcbcbc";
            renderStar(tmpContext, 3, obj.scale * 0.55, obj.scale * 0.65);
            tmpContext.fill();
        } else if (obj.name == "sapling") {
            for (var i = 0; i < 2; ++i) {
                var tmpScale = obj.scale * (!i?1:0.5);
                renderStar(tmpContext, 7, tmpScale, tmpScale * 0.7);
                tmpContext.fillStyle = (!i?"#9ebf57":"#b4db62");
                tmpContext.fill();
                if (!i) tmpContext.stroke();
            }
        } else if (obj.name == "pit trap") {
            tmpContext.fillStyle = "#a5974c";
            renderStar(tmpContext, 3, obj.scale * 1.1, obj.scale * 1.1);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.fillStyle = outlineColor;
            renderStar(tmpContext, 3, obj.scale * 0.65, obj.scale * 0.65);
            tmpContext.fill();
        } else if (obj.name == "boost pad") {
            tmpContext.fillStyle = "#7e7f82";
            renderRect(0, 0, obj.scale*2, obj.scale*2, tmpContext);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.fillStyle = "#dbd97d";
            renderTriangle(obj.scale * 1, tmpContext);
        } else if (obj.name == "turret") {
            tmpContext.fillStyle = "#a5974c";
            renderCircle(0, 0, obj.scale, tmpContext);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.fillStyle = "#939393";
            var tmpLen = 50;
            renderRect(0, -tmpLen/2, obj.scale * 0.9, tmpLen, tmpContext);
            renderCircle(0, 0, obj.scale * 0.6, tmpContext);
            tmpContext.fill();
            tmpContext.stroke();
        } else if (obj.name == "platform") {
            tmpContext.fillStyle = "#cebd5f";
            var tmpCount = 4;
            var tmpS = obj.scale * 2;
            var tmpW = tmpS / tmpCount;
            var tmpX = -(obj.scale/2);
            for (var i = 0; i < tmpCount; ++i) {
                renderRect(tmpX - (tmpW/2), 0, tmpW, obj.scale*2, tmpContext);
                tmpContext.fill();
                tmpContext.stroke();
                tmpX += tmpS / tmpCount;
            }
        } else if (obj.name == "healing pad") {
            tmpContext.fillStyle = "#7e7f82";
            renderRect(0, 0, obj.scale*2, obj.scale*2, tmpContext);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.fillStyle = "#db6e6e";
            renderRectCircle(0, 0, obj.scale * 0.65, 20, 4, tmpContext, true);
        } else if (obj.name == "spawn pad") {
            tmpContext.fillStyle = "#7e7f82";
            renderRect(0, 0, obj.scale*2, obj.scale*2, tmpContext);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.fillStyle = "#71aad6";
            renderCircle(0, 0, obj.scale * 0.6, tmpContext);
        } else if (obj.name == "blocker") {
            tmpContext.fillStyle = "#7e7f82";
            renderCircle(0, 0, obj.scale, tmpContext);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.rotate(Math.PI / 4);
            tmpContext.fillStyle = "#db6e6e";
            renderRectCircle(0, 0, obj.scale * 0.65, 20, 4, tmpContext, true);
        }  else if (obj.name == "teleporter") {
            tmpContext.fillStyle = "#7e7f82";
            renderCircle(0, 0, obj.scale, tmpContext);
            tmpContext.fill();
            tmpContext.stroke();
            tmpContext.rotate(Math.PI / 4);
            tmpContext.fillStyle = "#d76edb";
            renderCircle(0, 0, obj.scale * 0.5, tmpContext, true);
        }
        tmpSprite = tmpCanvas;
        if (!asIcon)
            itemSprites[spriteKey] = tmpSprite;
    }
    return tmpSprite;
}


function renderLeaf(x, y, l, r, ctxt) {
    var endX = x + (l * Math.cos(r));
    var endY = y + (l * Math.sin(r));
    var width = l * 0.4;
    ctxt.moveTo(x, y);
    ctxt.beginPath();
    ctxt.quadraticCurveTo(((x + endX) / 2) + (width * Math.cos(r + Math.PI/2)),
                          ((y + endY) / 2) + (width * Math.sin(r + Math.PI/2)), endX, endY);
    ctxt.quadraticCurveTo(((x + endX) / 2) - (width * Math.cos(r + Math.PI/2)),
                          ((y + endY) / 2) - (width * Math.sin(r + Math.PI/2)), x, y);
    ctxt.closePath();
    ctxt.fill();
    ctxt.stroke();
}

function inHitRange(building) {
    for (var i = 0; i < players.length; i++) {
        var p = players[i];
        var reach = combatManager.weaponReach(building, p.weaponIndex);
        var pdx = p.x2 - building.x, pdy = p.y2 - building.y;
        if (pdx * pdx + pdy * pdy <= reach * reach) return true;
    }
    return false;
}

function renderCircle(x, y, scale, tmpContext, dontStroke, dontFill) {
    tmpContext = tmpContext||mainContext;
    tmpContext.beginPath();
    tmpContext.arc(x, y, scale, 0, 2 * Math.PI);
    if (!dontFill) tmpContext.fill();
    if (!dontStroke) tmpContext.stroke();
}

function renderStar(ctxt, spikes, outer, inner) {
    var rot = Math.PI / 2 * 3;
    var x, y;
    var step = Math.PI / spikes;
    ctxt.beginPath();
    ctxt.moveTo(0, -outer);
    for (var i = 0; i < spikes; i++) {
        x = Math.cos(rot) * outer;
        y = Math.sin(rot) * outer;
        ctxt.lineTo(x, y);
        rot += step;
        x = Math.cos(rot) * inner;
        y = Math.sin(rot) * inner;
        ctxt.lineTo(x, y);
        rot += step;
    }
    ctxt.lineTo(0, -outer);
    ctxt.closePath();
}

function renderRect(x, y, w, h, ctxt, stroke) {
    ctxt.fillRect(x - (w / 2), y - (h / 2), w, h);
    if (!stroke)
        ctxt.strokeRect(x - (w / 2), y - (h / 2), w, h);
}

function renderRectCircle(x, y, s, sw, seg, ctxt, stroke) {
    ctxt.save();
    ctxt.translate(x, y);
    seg = Math.ceil(seg / 2);
    for (var i = 0; i < seg; i++) {
        renderRect(0, 0, s * 2, sw, ctxt, stroke);
        ctxt.rotate(Math.PI / seg);
    }
    ctxt.restore();
}

function renderBlob(ctxt, spikes, outer, inner) {
    var rot = Math.PI / 2 * 3;
    var x, y;
    var step = Math.PI / spikes;
    var tmpOuter;
    ctxt.beginPath();
    ctxt.moveTo(0, -inner);
    for (var i = 0; i < spikes; i++) {
        tmpOuter = UTILS.randInt(outer + 0.9, outer * 1.2);
        ctxt.quadraticCurveTo(Math.cos(rot + step) * tmpOuter, Math.sin(rot + step) * tmpOuter,
                              Math.cos(rot + (step * 2)) * inner, Math.sin(rot + (step * 2)) * inner);
        rot += step * 2;
    }
    ctxt.lineTo(0, -inner);
    ctxt.closePath();
}

function renderTriangle(s, ctx) {
    ctx = ctx||mainContext;
    var h = s * (Math.sqrt(3)/2);
    ctx.beginPath();
    ctx.moveTo(0, -h / 2);
    ctx.lineTo( -s / 2, h / 2);
    ctx.lineTo(s / 2, h / 2);
    ctx.lineTo(0, -h / 2);
    ctx.fill();
    ctx.closePath();
}

