function loadAI(data) {
    for (var i = 0; i < ais.length; ++i) {
        ais[i].forcePos = !ais[i].visible;
        ais[i].visible = false;
    }
    if (data) {
        var tmpTime = Date.now();
        for (var i = 0; i < data.length;) {
            tmpObj = findAIBySID(data[i]);
            if (tmpObj) {
                tmpObj.index = data[i + 1];
                tmpObj.t1 = (tmpObj.t2===undefined)?tmpTime:tmpObj.t2;
                tmpObj.t2 = tmpTime;
                tmpObj.x1 = tmpObj.x;
                tmpObj.y1 = tmpObj.y;
                tmpObj.x2 = data[i + 2];
                tmpObj.y2 = data[i + 3];
                tmpObj.d1 = (tmpObj.d2===undefined)?data[i + 4]:tmpObj.d2;
                tmpObj.d2 = data[i + 4];
                tmpObj.health = data[i + 5];
                tmpObj.dt = 0;
                tmpObj.visible = true;
            } else {
                tmpObj = aiManager.spawn(data[i + 2], data[i + 3], data[i + 4], data[i + 1]);
                tmpObj.x2 = tmpObj.x;
                tmpObj.y2 = tmpObj.y;
                tmpObj.d2 = tmpObj.dir;
                tmpObj.health = data[i + 5];
                if (!aiManager.aiTypes[data[i + 1]].name)
                    tmpObj.name = config.cowNames[data[i + 6]];
                tmpObj.forcePos = true;
                tmpObj.sid = data[i];
                tmpObj.visible = true;
            }
            i+=7;
        }
    }
}

var texturePack = new TexturePack();
var txtOverrides = (function() { try { var s = getSavedVal("texturePack"); var o = s ? JSON.parse(s) : {}; return o && typeof o === "object" ? o : {}; } catch (e) { return {}; } })();
if (!txtOverrides.hatTxt) txtOverrides.hatTxt = {};
if (!txtOverrides.accTxt) txtOverrides.accTxt = {};
if (!txtOverrides.aniTxt) txtOverrides.aniTxt = {};
function txtMasterOn() { return txtOverrides.master !== false; }
function hatTxtEnabled(id) { return txtMasterOn() && txtOverrides.hatTxt[id] !== false; }
function accTxtEnabled(id) { return txtMasterOn() && txtOverrides.accTxt[id] !== false; }
function aniTxtEnabled(id) { return txtMasterOn() && txtOverrides.aniTxt[id] !== false; }
