var customColors = ["#b0b0b0", "#6393bb", "#b356a6", "#689990", "#9983ae", "#709a72", "#ac7d9a", "#4a9ca5", "#798eb8", "#808cb4", "#a082a4", "#a77baf", "#7786da", "#b772ad", "#6a9a82", "#8a86be"];
var customColorMap = {};

var weaponXPTrack = [0, 0];
function xpLabel(slot) {
    var wid = player.weapons && player.weapons[slot];
    if (wid == null || !items.weapons[wid]) return "0/0";
    var xp = weaponXPTrack[slot] || 0;
    var V = config.weaponVariants;
    for (var i = 1; i < V.length; ++i) {
        if (xp < V[i].xp) return Math.floor(xp) + "/" + V[i].xp;
    }
    return Math.floor(xp) + "/max";
}

function customColor(sid) {
    if (sid == null || sid < 0) return "#fff";
    return customColorMap[sid] || (customColorMap[sid] = customColors[Math.floor(Math.random() * customColors.length)]);
}

var aiSprites = {};
function renderAI(obj, ctxt) {
    var tmpIndx = obj.index;
    var tmpSprite = aiSprites[tmpIndx];
    if (!tmpSprite) {
        var tmpImg = new Image();
        tmpImg.onload = function() {
            this.isLoaded = true;
            this.onload = null;
        };
        tmpImg.src = "./img/animals/" + obj.src + ".png";
        tmpSprite = tmpImg;
        aiSprites[tmpIndx] = tmpSprite;
    }

    if (tmpSprite.isLoaded) {
        var tmpScale = obj.scale * 1.2 * (obj.spriteMlt||1);
        ctxt.drawImage(tmpSprite, -tmpScale, -tmpScale, tmpScale*2, tmpScale*2);
    }

}

function isOnScreen(x, y, s) {
    return (x + s >= 0 && x - s <= maxScreenWidth && y + s >= 0 && y - s <= maxScreenHeight)
}

var playerStore = {};
var pendingEncounters = {};
function notePlayer(sid, name, o) {
    if (sid == null) return null;
    o = o || {};
    var rec = playerStore[sid];
    if (!rec) rec = playerStore[sid] = { sid: sid, pid: null, name: null, prevNames: [], seen: 0, lastSeen: 0, lbRank: 0, lbScore: 0, lastMsg: "", everReal: false, online: false };
    if (o.pid != null && rec.pid != null && o.pid !== rec.pid) { rec.prevNames = []; rec.seen = 0; rec.name = null; rec.lbRank = 0; rec.lbScore = 0; rec.lastMsg = ""; }
    if (name != null && name !== "" && name !== "unknown" && name !== rec.name) {
        if (rec.name != null) {
            var sameConn = o.pid != null && rec.pid != null ? o.pid === rec.pid : rec.online;
            if (sameConn) {
                if (rec.prevNames.indexOf(rec.name) < 0) rec.prevNames.push(rec.name);
                logPlayerEvent(nameTag(rec.name, sid, (findPlayerBySID(sid) || {}).team) + " has changed name to " + name);
            } else {
                rec.prevNames = []; rec.seen = 0; rec.lbRank = 0; rec.lbScore = 0; rec.lastMsg = "";
            }
        }
        rec.name = name;
    }
    if (o.encounter) rec.seen++;
    if (o.online === false) rec.lastSeen = Date.now();
    if (o.online != null) rec.online = o.online; else if (o.encounter) rec.online = true;
    if (o.pid != null) rec.pid = o.pid;
    if (o.lbRank != null) rec.lbRank = o.lbRank;
    if (o.lbScore != null) rec.lbScore = o.lbScore;
    if (o.lastMsg != null) rec.lastMsg = o.lastMsg;
    if (name || o.lbRank != null || o.encounter || o.online != null || o.lastMsg != null) rec.everReal = true;
    return rec;
}
function addPlayer(data, isYou) {
    var tmpPlayer = findPlayerByID(data[0]);
    if (!tmpPlayer) {
        tmpPlayer = new Player(data[0], data[1], config, UTILS, projectileManager,
                               objectManager, players, ais, items, hats, accessories);
        players.push(tmpPlayer);
        customColor(tmpPlayer.sid);
    }
    tmpPlayer.spawn(isYou?moofoll:null);
    tmpPlayer.visible = false;
    tmpPlayer.x2 = undefined;
    tmpPlayer.y2 = undefined;
    tmpPlayer.setData(data);
    var rec = notePlayer(tmpPlayer.sid, tmpPlayer.name, { online: true, encounter: true, pid: tmpPlayer.id });
    if (!isYou && rec) pendingEncounters[tmpPlayer.sid] = { name: tmpPlayer.name, ordinal: rec.seen };
    if (isYou) {
        player = tmpPlayer;
        aliveStart = Date.now();
        resyncArmTick = config.tick + 2;
        weaponXPTrack[0] = weaponXPTrack[1] = 0;
        player.barFill = null;
        camX = player.x;
        camY = player.y;
        renderMinimap();
        updateItems();
        updateStatusDisplay();
        updateAge();
        updateUpgrades(0);
        gameUI.style.display = "block";
        if (panelPages[0] && panelPages[0].hidden) showPanelPage(1);
    }
}

function removePlayer(id) {
    for (var i = 0; i < players.length; i++) {
        if (players[i].id == id) {
            notePlayer(players[i].sid, players[i].name, { online: false });
            delete pendingEncounters[players[i].sid];
            if (!player || players[i].sid !== player.sid) logPlayerEvent(nameTag(players[i].name, players[i].sid, players[i].team) + " has left");
            players.splice(i, 1);
            break;
        }
    }
}

function updateItemCounts(index, value) {
    if (player) {
        player.itemCounts[index] = value;
        updateItemCounter(index);
    }
}

function groupPlaceLimit(item) {
    return config.inSandbox ? (item.group.sandboxLimit || Math.max(item.group.limit * 3, 99)) : item.group.limit;
}

function attachItemCounters() {
    for (var i = 0; i < items.list.length; ++i) {
        var item = items.list[i];
        var el = document.getElementById("actionBarItem" + (items.weapons.length + i));
        if (!el) continue;
        if (item.group && item.group.id === 0 && item.req && item.req[0] === "food") {
            var fspan = document.createElement("span");
            fspan.className = "itemCounter";
            fspan.setAttribute("data-food-cost", item.req[1]);
            el.appendChild(fspan);
            continue;
        }
        if (!item.group || !item.group.limit) continue;
        var span = document.createElement("span");
        span.className = "itemCounter";
        span.setAttribute("data-group", item.group.id);
        span.setAttribute("data-limit", groupPlaceLimit(item));
        span.textContent = ((player && player.itemCounts[item.group.id]) || 0) + "/" + groupPlaceLimit(item);
        el.appendChild(span);
    }
}

function refreshFoodCounters() {
    if (!player) return;
    var food = player.food || 0;
    var spans = document.querySelectorAll("span.itemCounter[data-food-cost]");
    for (var i = 0; i < spans.length; ++i) {
        var cost = +spans[i].getAttribute("data-food-cost");
        var infinite = config.inSandbox && food >= cost;
        spans[i].textContent = infinite ? "-1" : food;
    }
}

function updateItemCounter(group) {
    var count = (player && player.itemCounts[group]) || 0;
    var spans = document.querySelectorAll("span.itemCounter[data-group='" + group + "']");
    for (var i = 0; i < spans.length; ++i) spans[i].textContent = count + "/" + spans[i].getAttribute("data-limit");
}

function updatePlayerValue(index, value, updateView) {
    if (player) {
        if ((index === "wood" || index === "food" || index === "stone") && player.weaponIndex != null) {
            var previousRes = player[index] || 0;
            if (value > previousRes) weaponXPTrack[player.weaponIndex < 9 ? 0 : 1] += (value - previousRes);
        }
        player[index] = value;
        if (updateView)
            updateStatusDisplay();
    }
}

function updateHealth(sid, value) {
    tmpObj = findPlayerBySID(sid);
    if (tmpObj) {
        var diff = tmpObj.health - value;
        if (diff > 0) {
            tmpObj.lastHurtTick = config.tick; tmpObj.receivedDamage = Date.now();
            if (tmpObj._dmgTick === config.tick) tmpObj._dmgAcc += diff;
            else { tmpObj._dmgTick = config.tick; tmpObj._dmgAcc = diff; }
            if (settings.visuals.dmgText && tmpObj !== player) tmpObj.stackDmg = (tmpObj.stackDmg > 0 ? tmpObj.stackDmg : 0) + diff;
        }
        if (tmpObj === player && (diff === 25 || diff === 50 || (player.skinIndex === 6 && (diff === 18 || diff === 19 || diff === 37 || diff === 38)))) {
            var kbe = combatIntel.nearestEnemy;
            if (kbe && combatIntel.near(player, kbe, 300) && combatIntel.nearestSpike
                && (combatIntel.nearestSpike.x - player.x2) * (combatIntel.nearestSpike.x - player.x2) + (combatIntel.nearestSpike.y - player.y2) * (combatIntel.nearestSpike.y - player.y2) <= 350 * 350) {
                player.turretShotKB = config.tick;
            }
        }
        else if (diff < 0 && tmpObj !== player && tmpObj.receivedDamage) {
            var step = Date.now() - tmpObj.receivedDamage;
            tmpObj.receivedDamage = 0;
            var fastHeal = step <= 120;
            tmpObj.shameCount = Math.max(0, (tmpObj.shameCount || 0) + (fastHeal ? 1 : -2));
            if (tmpObj.shameCount >= 8) tmpObj.shameCount = 0;
            var samples = fastHeal ? (tmpObj.shameUp || (tmpObj.shameUp = [])) : (tmpObj.shameDown || (tmpObj.shameDown = []));
            if (samples.length >= 5) samples.shift();
            samples.push(step);
            var speedAvg = samples.reduce(function(a, b) { return a + b; }, 0) / samples.length;
            if (fastHeal) tmpObj.gainSpeed = speedAvg; else tmpObj.leakSpeed = speedAvg;
        }
        if (diff === 2 || diff === 5) {
            if (tmpObj !== player || config.tick - tmpObj.bullTick >= 7 || (resyncBullTick && diff === 5 && player.skinIndex === 7)) tmpObj.bullTick = config.tick;
        }
        if (tmpObj === player && resyncBullTick && diff >= 2 && player.skinIndex === 7) { resyncBullTick = false; logPlayerEvent("Resynced Bull Tick at T." + config.tick, "#89c562"); }
        if (diff === 5 && tmpObj.skinIndex !== 7 && player && !isAlly(tmpObj.sid)) tmpObj.poisonCount = Math.max(tmpObj.poisonCount || 0, 5);
        if (diff !== 0) {
            if (!tmpObj.deathDmgs) tmpObj.deathDmgs = [];
            var ddVal = Math.round(-diff * 100) / 100;
            var ddLast = tmpObj.deathDmgs[tmpObj.deathDmgs.length - 1];
            if (ddLast && ddLast.tick === config.tick) ddLast.dmgs.push(ddVal);
            else tmpObj.deathDmgs.push({ tick: config.tick, dmgs: [ddVal] });
        }
        tmpObj.health = value;
        if (value >= (tmpObj.maxHealth || 100)) tmpObj.deathDmgs = [];
        if (tmpObj.health <= 0) {
            if (!tmpObj._deathLogged) {
                tmpObj._deathLogged = true;
                var ddStr = (tmpObj.deathDmgs || []).map(function(g) { return "[" + g.dmgs.join(", ") + "]"; }).join(", ");
                logPlayerEvent(nameTag(tmpObj.name, tmpObj.sid, tmpObj.team) + " has died to damages " + ddStr);
                tmpObj.deathDmgs = [];
            }
            if (!tmpObj._deathGhosted) { createDeathGhost(tmpObj); tmpObj._deathGhosted = true; }
            if (!tmpObj._shattered) { createShatter(tmpObj); tmpObj._shattered = true; }
        } else {
            tmpObj._deathGhosted = false;
            tmpObj._shattered = false;
            tmpObj._deathLogged = false;
        }
    }
}

function place(id, dir = getAttackDir()) {
    io.send("z", id, 0);
    io.send("D", dir);
    io.send("F", 1, dir);
    combatManager.attackHeld = true;
    io.send("z", player.weaponIndex, 1);
}

function updatePlayers(data) {
    config.tick++;
    if (config.tick % 9 === 0) config.packets = 0;
    if (resyncArmTick && config.tick >= resyncArmTick) {
        resyncArmTick = 0;
        if (inGame && player && player.alive && combatManager.ownsItem(0, 7) && !resyncBullTick && !autoFarm.farmToggle && (!combatIntel.nearestEnemy || combatIntel.nearestEnemy.distanceToMe > 300)) { resyncBullTick = true; logPlayerEvent("Resyncing Bull Tick at T." + config.tick, "#e8a33d"); }
    }
    flushTextBuffer();
    advanceFakeGhosts();
    combatIntel.enemies.length = 0;
    var tmpTime = Date.now();
    rebuildActiveTraps();
    for (var i = 0; i < players.length; ++i) {
        players[i].forcePos = !players[i].visible;
        players[i].visible = false;
    }
    for (var i = 0; i < data.length;) {
        tmpObj = findPlayerBySID(data[i]);
        if (tmpObj) {
            tmpObj.t1 = (tmpObj.t2===undefined)?tmpTime:tmpObj.t2;
            tmpObj.t2 = tmpTime;
            tmpObj.x1 = tmpObj.x;
            tmpObj.y1 = tmpObj.y;
            tmpObj.px = tmpObj.x2;
            tmpObj.py = tmpObj.y2;
            tmpObj.lastPredicted = tmpObj.predicted;
            tmpObj.lastMoveDir = tmpObj.moveDir;
            tmpObj.x2 = data[i + 1];
            tmpObj.y2 = data[i + 2];
            tmpObj.vx = (tmpObj.px===undefined || tmpObj.px !== tmpObj.px)?0:tmpObj.x2 - tmpObj.px;
            tmpObj.vy = (tmpObj.py===undefined || tmpObj.py !== tmpObj.py)?0:tmpObj.y2 - tmpObj.py;
            tmpObj.moveDir = (tmpObj.px===undefined || (tmpObj.x2===tmpObj.px && tmpObj.y2===tmpObj.py))?undefined:Math.atan2(tmpObj.y2 - tmpObj.py, tmpObj.x2 - tmpObj.px);
            tmpObj.d1 = (tmpObj.d2===undefined)?data[i + 3]:tmpObj.d2;
            tmpObj.d2 = data[i + 3];
            tmpObj.dt = 0;
            tmpObj.buildIndex = data[i + 4];
            if (tmpObj.buildIndex >= 0 && tmpObj.updateInventory) tmpObj.updateInventory(tmpObj.buildIndex);
            tmpObj.weaponIndex = data[i + 5];
            tmpObj.weaponVariant = data[i + 6];
            tmpObj.team = data[i + 7];
            if (pendingEncounters[tmpObj.sid]) {
                var pe = pendingEncounters[tmpObj.sid];
                delete pendingEncounters[tmpObj.sid];
                logPlayerEvent(pe.ordinal > 1
                               ? "Encountered " + nameTag(pe.name, tmpObj.sid, tmpObj.team) + " for the " + ordinal(pe.ordinal) + " time"
                               : "Encountered " + nameTag(pe.name, tmpObj.sid, tmpObj.team));
            }
            tmpObj.isLeader = data[i + 8];
            tmpObj.skinIndex = data[i + 9];
            if (tmpObj.skinIndex === 45) {
                tmpObj.shameCount = 0;
                if (!tmpObj.shameTimer) tmpObj.shameTimer = Date.now();
            } else tmpObj.shameTimer = 0;
            tmpObj.tailIndex = data[i + 10];
            tmpObj.iconIndex = data[i + 11];
            tmpObj.zIndex = data[i + 12];
            tmpObj.trappedPrevious = tmpObj.trapped;
            tmpObj.trapped = trapped(tmpObj);
            tmpObj.predicted = velocity.predict(tmpObj);
            combatIntel.predictWeapons(tmpObj);
            weaponReloads.tick(tmpObj);
            tmpObj.visible = true;
            if (tmpObj.poisonCount > 0 && tmpObj.isBullTickTime(0)) tmpObj.poisonCount = Math.max(tmpObj.poisonCount - 1, 0);
            if (player && !isAlly(tmpObj.sid)) {
                combatIntel.enemies.push(tmpObj);
            }
        }
        i+=13;
    }

    hitResolver.settle(projectileOwner);

    if (inGame && player?.alive) {
        var _perfStart = performance.now();
        objectManager.buildNearObjects(player);
        combatIntel.handleEnemies(player);
        if (settings.visuals.trapGhosts) updateTrapGhosts(player);
        preArmKbLanding(player);
        combatManager.tick(player, getAttackDir(), attackState, lastMoveDir, getMoveDir(), getClickAim());
        sendMoveDir();
        combatManager.stopMove = false;
        if (settingAllows("Auto Place")) autoPlace.managePreplace();

        if (!combatManager.placed && !combatManager.active) {
            autoWindmills.toggle && autoWindmills.update(player, lastMoveDir, place);
            if (placeGroup !== null) {
                for (var pg = 0; pg < placeGroup.length; ++pg) {
                    var placeId = combatManager.idForGroup(placeGroup[pg]);
                    if (placeId !== null && player.canBuild(items.list[placeId])) { place(placeId); break; }
                }
            }
        }
        if (!attackState.attacking && combatManager.attackHeld && combatIntel.trapMeltDamage <= 0) combatManager.releaseAttack();

        if (combatManager.swBreak) swBreakTick = config.tick;
        var swText = null;
        var swBreaking = combatManager.swBreak || (combatManager.wouldStop && combatManager.swBreakable && config.tick - swBreakTick <= 5);
        if (combatManager.shiftHeld && combatManager.wouldStop) swText = "override";
        else if (swBreaking) swText = "sw-break";
        else if (combatManager.wouldStop) swText = "stop";
        if (swText && settings.visuals.feedbackText && (swText !== lastSWText || Date.now() - lastSWTTime >= 500)) {
            textManager.showText(player.x, player.y, 18, .1, 500, swText, "#fff", null, 8);
            lastSWTTime = Date.now();
        }
        lastSWText = swText;
        perfExec = Math.round(performance.now() - _perfStart);
    }
}

